// Global variable
int x = 10;

int main() {
 // Local variable with same name
 int x = 5;

 cout << "Local x: " << x << endl; // Prints 5
 cout << "Global x: " << ::x << endl; // Prints 10

 return 0;
}

class MyClass {
public:
 void display(); // Function prototype
 int getValue();
};

// Define outside class using ::
void MyClass::display() {
 cout << "Display function" << endl;
}

int MyClass::getValue() {
 return 100;
}

int main() {
 MyClass obj;
 obj.display(); // Prints: Display function
 cout << obj.getValue(); // Prints: 100
 return 0;
}

// Enum class - strongly typed enumeration
enum class Color {
 Red,
 Green,
 Blue
};

int main() {
 Color c = Color::Red; // Must use :: to access

 if (c == Color::Red) {
 cout << "Color is Red" << endl;
 }

 // Cannot do: int x = Red; // Error!
 // Must do: int x = (int)Color::Red;

 return 0;
}

class Base {
public:
 void display() {
 cout << "Base display" << endl;
 }
};

class Derived : public Base {
public:
 void display() {
 cout << "Derived display" << endl;
 }

 void showBase() {
 Base::display(); // Access base class version
 }
};

int main() {
 Derived obj;
 obj.display(); // Calls Derived::display()
 obj.Base::display(); // Explicitly calls Base::display()
 return 0;
}

class Counter {
public:
 static int count; // Declaration

 Counter() {
 count++;
 }

 static void getCount() {
 cout << "Count: " << count << endl;
 }
};

// Definition using :: - MUST be outside
int Counter::count = 0;

int main() {
 Counter c1, c2, c3;
 Counter::getCount(); // Access static without object
 return 0;
}

#include <iostream>
using std::cout; // Only bring specific names
using std::endl;

int main() {
 // Explicit qualification (preferred)
 std::cout << "Using std::cout" << std::endl;

 // Using imported names
 cout << "Using 'using' for specific names" << endl;

 // Avoid: using namespace std; // Bad practice

 return 0;
}
